  const telLine = source
    .split(/\r?\n/)
    .map((line) => line.trim())
    .find((line) => /^TEL(?:;[^:]*)?:/i.test(line));

  if (!telLine) return null;

  const parts = telLine.split(/:(.+)/, 2);
  const phonePart = parts[1] || "";
  return normPhone(phonePart);
}

