const chatId = toStr(command.targetExternalChatId) || toStr(command.targetExternalUserId);
const content = toStr(command.text);
if (!chatId || !content) {
  return [null, Object.assign({}, msg, { payload: { error: "Missing target or text", command } })];
}

const formattedText = command && command.meta && typeof command.meta.formattedText === "string" && command.meta.formattedText.trim()
  ? command.meta.formattedText.trim()
  : null;

const sendPayload = command && command.format && formattedText
  ? { text: formattedText, format: command.format }
  : content;

const sendMsg = Object.assign({}, msg, {
  supportOutbox: command,
  chatId,
  payload: sendPayload,
});

return [sendMsg, null];

const isObj = (value) => value && typeof value === "object" && !Array.isArray(value);
const toStr = (value) => {
  if (value === null || value === undefined) return null;
  const normalized = String(value).trim();
  return normalized ? normalized : null;
};

const update = isObj(msg.maxUpdate) ? msg.maxUpdate : null;
if (!update) return null;
if (!(update.messageKind === "station" && update.station && update.callbackId)) return null;

const token = (() => {
  try {
    return toStr(env.get("MAX_ACADEMY_BOT_ACCESS_TOKEN"));
  } catch {
    return null;
  }
})();

if (!token) {
  node.warn("MAX_ACADEMY_BOT_ACCESS_TOKEN is empty, callback answer skipped");
  return null;
}

msg.method = "POST";
msg.url = "https://platform-api.max.ru/answers?callback_id=" + encodeURIComponent(update.callbackId);
msg.headers = {
  "Content-Type": "application/json",
  "Authorization": token
};
msg.payload = {
  message: {
    text: "Станция выбрана: " + update.station.name,
    attachments: []
  }
};
return msg;
